  'strategy.label': { en: 'BOOK A 30-MINUTE CALL', fr: 'RÉSERVER UN APPEL DE 30 MINUTES', hu: 'FOGLALJON 30 PERCES HÍVÁST' },
  'strategy.title': { en: 'Book your', fr: 'Réservez votre', hu: 'Foglalja le a' },
